codeExamples.code:
CREATE TABLE daily_sales (
    sale_date DATE PRIMARY KEY,
    daily_total DECIMAL(10,2)
);

INSERT INTO daily_sales VALUES
('2026-04-01',  5000),
('2026-04-02',  8000),
('2026-04-03',  6500),
('2026-04-04',  9200),
('2026-04-05',  7100);

SELECT sale_date, daily_total,
       SUM(daily_total) OVER (ORDER BY sale_date
           ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
       ) AS running_total
FROM daily_sales
ORDER BY sale_date;

commonMistakes.correctCode:
-- DENSE_RANK is tie-aware
SELECT DISTINCT salary FROM (
    SELECT salary, DENSE_RANK() OVER (ORDER BY salary DESC) AS rnk
    FROM employees
) t WHERE rnk = 3;

commonMistakes.wrongCode:
SELECT * FROM customers
WHERE id NOT IN (SELECT customer_id FROM orders);
-- If orders has a row with customer_id = NULL, this returns ZERO rows.

commonMistakes.correctCode:
SELECT * FROM customers
WHERE id NOT IN (SELECT customer_id FROM orders WHERE customer_id IS NOT NULL);

-- Or use NOT EXISTS, which is not affected by NULLs
SELECT * FROM customers c
WHERE NOT EXISTS (
    SELECT 1 FROM orders o WHERE o.customer_id = c.id
);

SELECT dept, salary FROM (
    SELECT dept, salary, DENSE_RANK() OVER (
        PARTITION BY dept ORDER BY salary DESC
    ) AS rnk
    FROM employees
) t
WHERE rnk = 2;

commonMistakes.wrongCode:
SELECT dept FROM employees
WHERE COUNT(*) > 5;
-- ERROR 1111 (HY000): Invalid use of group function

commonMistakes.correctCode:
SELECT dept FROM employees
GROUP BY dept
HAVING COUNT(*) > 5;
